SELECT building_id, spot_name, name, type, nearest_node_id
FROM buildings
WHERE spot_name = #{spotName}
   OR (
     NOT EXISTS (SELECT 1 FROM buildings WHERE spot_name = #{spotName})
     AND (
       spot_name LIKE '%' || #{spotName} || '%'
       OR #{spotName} LIKE '%' || spot_name || '%'
     )
   )

SELECT building_id, spot_name, name, type, nearest_node_id
FROM buildings
WHERE (spot_name = #{spotName}
   OR (
     NOT EXISTS (SELECT 1 FROM buildings WHERE spot_name = #{spotName})
     AND (
       spot_name LIKE '%' || #{spotName} || '%'
       OR #{spotName} LIKE '%' || spot_name || '%'
     )
   ))
  AND type = #{type}

SELECT building_id, spot_name, name, type, nearest_node_id
FROM buildings
WHERE building_id = #{buildingId}
